#!/usr/bin/env python3
"""mesh-timeprofile - "where does the time go" breakdown of a distributed forward.

For each node configuration it runs the forward and attributes every stage's
wall-clock to two buckets using fat-station's `X-Compute-Ms` response header:

    station compute  = X-Compute-Ms      (pure kernel time on that node)
    wire/overhead    = client RTT - X-Compute-Ms
                       (USB/adb-forward transfer + HTTP framing + serialization)

So you can see whether latency lives in COMPUTE (the slow R1 ARM CPU running its
layer slice) or in the WIRE (USB round-trips, HTTP) - which decides what to
optimize. Reports the warm median per stage over --runs.

Endpoints + test vector identical to mesh-shootout.py (env MESH_MAC/R1A/R1B).

Usage:
  python3 mesh-timeprofile.py [--runs N] [--layers L] [--tokens a,b,c] [--expect ID]
"""
import argparse, os, struct, sys, time, urllib.request, urllib.error, statistics

MAC = os.environ.get("MESH_MAC", "http://127.0.0.1:8080")
R1A = os.environ.get("MESH_R1A", "http://127.0.0.1:8090")
R1B = os.environ.get("MESH_R1B", "http://127.0.0.1:8091")


def up(base):
    try:
        urllib.request.urlopen(base + "/health", timeout=4).read(); return True
    except (urllib.error.URLError, OSError):
        return False


def stage(base, path, body, headers):
    """POST and return (reply_bytes, rtt_ms, compute_ms, sent_bytes)."""
    req = urllib.request.Request(base + path, data=body, method="POST")
    for k, v in headers.items():
        req.add_header(k, v)
    t0 = time.time()
    with urllib.request.urlopen(req, timeout=300) as r:
        data = r.read()
        compute = int(r.headers.get("X-Compute-Ms", -1))
    return data, (time.time() - t0) * 1000, compute, len(body)


def even_cuts(nodes, layers):
    n = len(nodes)
    return [(nodes[i], i * layers // n, (i + 1) * layers // n) for i in range(n)]


def profile_once(tokens, seq, embed, cuts, head):
    """Return list of (label, rtt_ms, compute_ms, bytes_in) per stage + argmax."""
    rows = []
    body = struct.pack("<%dI" % len(tokens), *tokens)
    buf, rtt, comp, nb = stage(embed, "/embed", body, {"X-Position": "0"})
    rows.append(("embed", rtt, comp, nb))
    for node, lo, hi in cuts:
        buf, rtt, comp, nb = stage(node, "/forward", buf,
                                   {"X-Position": "0", "X-Sequence-Length": str(seq),
                                    "X-Layer-Range": f"{lo}-{hi}"})
        rows.append((f"forward {lo}-{hi}", rtt, comp, nb))
    rep, rtt, comp, nb = stage(head, "/lm-head", buf, {"X-Sequence-Length": str(seq)})
    rows.append(("lm-head", rtt, comp, nb))
    logits = struct.unpack("<%df" % (len(rep) // 4), rep)
    return rows, max(range(len(logits)), key=lambda i: logits[i])


def main():
    ap = argparse.ArgumentParser(description="distributed-forward time breakdown")
    ap.add_argument("--runs", type=int, default=7)
    ap.add_argument("--layers", type=int, default=24)
    ap.add_argument("--tokens", default="785,6722,315,9625,374")
    ap.add_argument("--expect", type=int, default=12095)
    ap.add_argument("--vary", action="store_true",
                    help="fresh random prompt per run so the KV cache can't short-circuit "
                         "the layers (measures UNCACHED compute; disables argmax check)")
    ap.add_argument("--vocab", type=int, default=151936, help="vocab size for --vary token sampling")
    args = ap.parse_args()
    import random
    fixed = [int(x) for x in args.tokens.split(",")]
    seq = len(fixed)
    rng = random.Random(1)
    next_tokens = (lambda: [rng.randrange(1, args.vocab) for _ in range(seq)]) if args.vary else (lambda: fixed)

    have = {"Mac": MAC if up(MAC) else None, "R1a": R1A if up(R1A) else None, "R1b": R1B if up(R1B) else None}
    mac, r1a, r1b = have["Mac"], have["R1a"], have["R1b"]
    cfgs = []
    if mac:
        cfgs.append(("Mac only", mac, [(mac, 0, args.layers)], mac))
    if r1a:
        cfgs.append(("R1 only", r1a, [(r1a, 0, args.layers)], r1a))
    if r1a and r1b:
        c = even_cuts([r1a, r1b], args.layers); cfgs.append(("R1 + R1", c[0][0], c, c[-1][0]))
    if mac and r1a and r1b:
        c = even_cuts([mac, r1a, r1b], args.layers); cfgs.append(("Mac + R1 + R1", c[0][0], c, c[-1][0]))
    print("stations:", ", ".join(f"{k}={'up' if v else 'down'}" for k, v in have.items()), f"  (warm median of {args.runs})\n")

    for name, emb, cuts, head in cfgs:
        # warm (page in weights)
        profile_once(next_tokens(), seq, emb, cuts, head)
        samples, amax = [], None
        for _ in range(args.runs):
            rows, amax = profile_once(next_tokens(), seq, emb, cuts, head); samples.append(rows)
        n_stages = len(samples[0])
        tag = "(varied prompts, uncached)" if args.vary else (
            "(argmax %d OK)" % amax if amax == args.expect else "(argmax %d WRONG)" % amax)
        print(f"--- {name} {tag} ---")
        print(f"  {'stage':<14} {'rtt ms':>7} {'compute':>8} {'wire/oh':>8} {'sent B':>8}")
        tot_rtt = tot_comp = 0.0
        for i in range(n_stages):
            label = samples[0][i][0]
            rtt = statistics.median(s[i][1] for s in samples)
            comp = statistics.median(s[i][2] for s in samples)
            nb = samples[0][i][3]
            oh = rtt - comp
            tot_rtt += rtt; tot_comp += comp
            print(f"  {label:<14} {rtt:>7.1f} {comp:>8.0f} {oh:>8.1f} {nb:>8}")
        print(f"  {'TOTAL':<14} {tot_rtt:>7.1f} {tot_comp:>8.0f} {tot_rtt-tot_comp:>8.1f}")
        print(f"  -> compute {tot_comp/tot_rtt*100:.0f}%   wire/overhead {(tot_rtt-tot_comp)/tot_rtt*100:.0f}%\n")
    return 0


if __name__ == "__main__":
    sys.exit(main())
